parameters.inputSchema:
{
	"type": "object",
	"properties": {
		"priorityScore": {
			"type": "number",
			"minimum": 0,
			"maximum": 100,
			"description": "Numerical priority score from 0 to 100"
		},
		"priorityLevel": {
			"type": "string",
			"enum": ["critical", "high", "medium", "low"],
			"description": "Priority level classification"
		},
		"riskAssessment": {
			"type": "string",
			"description": "Assessment of risks associated with the signal"
		},
		"impactAnalysis": {
			"type": "string",
			"description": "Analysis of potential impact"
		},
		"recommendedActions": {
			"type": "array",
			"items": {
				"type": "string"
			},
			"description": "List of recommended actions to take"
		},
		"requiresEscalation": {
			"type": "boolean",
			"description": "Whether this signal requires escalation"
		},
		"reasoning": {
			"type": "string",
			"description": "Reasoning behind the prioritization decision"
		}
	},
	"required": ["priorityScore", "priorityLevel", "riskAssessment", "impactAnalysis", "recommendedActions", "requiresEscalation", "reasoning"]
}

